/// Fork/join of two closures — frf's drop-in for `rayon::join`. Spawns `b` on a
/// scoped worker, runs `a` on the current thread, folds the results into `(A, B)`:
/// the fork (spawn) / race (both run) / fold (join) triad for exactly two tasks.
/// Nesting is safe — frf's `is_in_pool` guard keeps inner parallel sections from
/// oversubscribing. On wasm32 (no threads) it runs serially.
#[cfg(not(target_arch = "wasm32"))]
pub fn join<A, B, RA, RB>(a: A, b: B) -> (RA, RB)
where
    A: FnOnce() -> RA + Send,
    B: FnOnce() -> RB + Send,
    RA: Send,
    RB: Send,
{
    std::thread::scope(|s| {
        let h = s.spawn(b);
        let ra = a();
        let rb = h.join().expect("gnosis_frf::join: second task panicked");
        (ra, rb)
    })
}

/// wasm32 has no threads: run the two tasks serially.
#[cfg(target_arch = "wasm32")]
pub fn join<A, B, RA, RB>(a: A, b: B) -> (RA, RB)
where
    A: FnOnce() -> RA,
    B: FnOnce() -> RB,
{
    (a(), b())
}

#[cfg(test)]
mod join_tests {
    #[test]
    fn join_returns_both_results() {
        let (a, b) = super::join(|| 2 + 3, || 10 * 4);
        assert_eq!((a, b), (5, 40));
    }

    #[test]
    fn join_runs_both_closures() {
        use std::sync::atomic::{AtomicU32, Ordering};
        let c = AtomicU32::new(0);
        super::join(
            || {
                c.fetch_add(1, Ordering::SeqCst);
            },
            || {
                c.fetch_add(10, Ordering::SeqCst);
            },
        );
        assert_eq!(c.load(Ordering::SeqCst), 11);
    }

    #[test]
    fn join_handles_large_disjoint_writes() {
        let mut a = vec![0u64; 1000];
        let mut b = vec![0u64; 1000];
        super::join(
            || a.iter_mut().enumerate().for_each(|(i, x)| *x = i as u64),
            || b.iter_mut().enumerate().for_each(|(i, x)| *x = (i * 2) as u64),
        );
        assert_eq!(a[999], 999);
        assert_eq!(b[999], 1998);
    }
}
